import fs from 'fs';
import path from 'path';

/**
 * MAKE MIGRATION IDEMPOTENT
 *
 * Transforms a Supabase migration file (generated by `supabase migration squash`)
 * so it can be safely re-applied on a database that already has some or all objects.
 *
 * Transformations:
 *   1. ADD CONSTRAINT        → wrapped in DO $$ IF NOT EXISTS (pg_constraint) ... END $$
 *   2. CREATE POLICY          → prepended with DROP POLICY IF EXISTS
 *   3. CREATE INDEX           → CREATE INDEX IF NOT EXISTS
 *   4. CREATE UNIQUE INDEX    → CREATE UNIQUE INDEX IF NOT EXISTS
 *   5. CREATE TYPE ... AS ENUM → wrapped in DO $$ IF NOT EXISTS (pg_type) ... END $$
 *   6. ALTER PUBLICATION ADD TABLE → wrapped in DO $$ IF NOT EXISTS check
 *
 * Usage:
 *   node scripts/make-migration-idempotent.mjs [path]
 *
 *   path  Optional. If omitted, processes ALL .sql files in supabase/migrations/.
 *         If provided, processes only the specified file.
 */

const MIGRATIONS_DIR = path.resolve('supabase/migrations');

// ---------------------------------------------------------------------------
// Resolve target file
// ---------------------------------------------------------------------------

function resolveTargets() {
  const explicit = process.argv[2];

  if (explicit) {
    const resolved = path.resolve(explicit);

    if (!fs.existsSync(resolved)) {
      console.error(`File not found: ${resolved}`);
      process.exit(1);
    }

    return [resolved];
  }

  const files = fs.readdirSync(MIGRATIONS_DIR).filter((f) => f.endsWith('.sql'));

  if (files.length === 0) {
    console.error('No .sql files found in supabase/migrations/');
    process.exit(1);
  }

  return files.map((f) => path.join(MIGRATIONS_DIR, f));
}

// ---------------------------------------------------------------------------
// Transformation helpers
// ---------------------------------------------------------------------------

function wrapConstraints(content) {
  let count = 0;

  const re = /^(ALTER TABLE ONLY [^\n]+\n\s+ADD CONSTRAINT "([^"]+)"[^;]+;)/gm;

  content = content.replace(re, (_match, full, conname) => {
    count++;

    const indented = full.replace(/\n\s+/g, '\n        ');

    return [
      `DO $$ BEGIN`,
      `  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = '${conname}') THEN`,
      `    ${indented}`,
      `  END IF;`,
      `END $$;`,
    ].join('\n');
  });

  return { content, count };
}

function addDropPolicies(content) {
  let count = 0;

  const re = /CREATE POLICY "([^"]+)"\s+ON ((?:"[^"]+"\.?"[^"]+")|(?:[a-z_]+\.[a-z_]+))/g;
  const replacements = [];

  let m;

  while ((m = re.exec(content)) !== null) {
    const before = content.substring(Math.max(0, m.index - 200), m.index);

    if (before.includes(`DROP POLICY IF EXISTS "${m[1]}"`)) {
      continue;
    }

    replacements.push({
      index: m.index,
      policyName: m[1],
      tableRef: m[2],
    });
  }

  for (let i = replacements.length - 1; i >= 0; i--) {
    const { index, policyName, tableRef } = replacements[i];
    const dropLine = `DROP POLICY IF EXISTS "${policyName}" ON ${tableRef};\n`;

    content = content.substring(0, index) + dropLine + content.substring(index);

    count++;
  }

  return { content, count };
}

function wrapAddColumn(content) {
  let count = 0;

  // Match: ALTER TABLE [ONLY] <table> ADD COLUMN <col> <rest>;
  // Handles both quoted ("public"."surveys") and unquoted (public.surveys) table names
  // and multi-line statements ending with ;
  const re = /^(ALTER TABLE (?:ONLY )?((?:"[^"]+"\.?"[^"]+")|(?:[a-z_]+\.[a-z_]+))\s*\n?\s*ADD COLUMN (?!IF NOT EXISTS)("?)([^"\s]+)\3[^;]+;)/gm;

  content = content.replace(re, (match, _full, _table, _quote, _colName) => {
    count++;
    return match.replace(/ADD COLUMN (?!IF NOT EXISTS)/, 'ADD COLUMN IF NOT EXISTS ');
  });

  return { content, count };
}

function addIndexIfNotExists(content) {
  let count = 0;

  content = content.replace(/CREATE (UNIQUE )?INDEX (?!IF NOT EXISTS)/g, (_match, unique) => {
    count++;
    return `CREATE ${unique || ''}INDEX IF NOT EXISTS `;
  });

  return { content, count };
}

function wrapCreateTypes(content) {
  let count = 0;

  const re =
    /^(CREATE TYPE "([^"]+)"\."([^"]+)" AS ENUM \(\n(?:[\s\S]*?\n)\);)\n(\n*(?:ALTER TYPE "([^"]+)"\."([^"]+)" OWNER TO "[^"]+";\n)?)/gm;

  content = content.replace(re, (_match, createStmt, _schema, typeName, trailing) => {
    count++;

    const indented = createStmt.replace(/\n/g, '\n    ');

    const lines = [
      `DO $$ BEGIN`,
      `  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = '${typeName}') THEN`,
      `    ${indented}`,
      `  END IF;`,
      `END $$;`,
      '',
      trailing.trim() ? trailing.trim() : '',
    ];

    return lines.filter((l) => l !== '').join('\n') + '\n';
  });

  return { content, count };
}

function stripAuthTriggers(content) {
  let count = 0;

  const re = /^CREATE OR REPLACE TRIGGER [^\n]+ ON "auth"\."[^"]+".+;$/gm;

  content = content.replace(re, (match) => {
    count++;

    const lines = [
      `-- [REMOVED BY make-migration-idempotent] The following trigger targets the`,
      `-- auth schema which cannot be managed by \`supabase db push\`.`,
      `-- Apply it manually via Supabase Dashboard. See: supabase/auth_trigger.sql`,
      `-- ${match}`,
    ];

    return lines.join('\n');
  });

  return { content, count };
}

function wrapPublicationAddTable(content) {
  let count = 0;

  const re = /^ALTER PUBLICATION "([^"]+)" ADD TABLE ONLY "([^"]+)"\."([^"]+)";/gm;

  content = content.replace(re, (_match, pubName, schema, table) => {
    count++;

    return [
      `DO $$ BEGIN`,
      `  IF NOT EXISTS (`,
      `    SELECT 1 FROM pg_publication_tables`,
      `    WHERE pubname = '${pubName}'`,
      `      AND schemaname = '${schema}'`,
      `      AND tablename = '${table}'`,
      `  ) THEN`,
      `    ALTER PUBLICATION "${pubName}" ADD TABLE ONLY "${schema}"."${table}";`,
      `  END IF;`,
      `END $$;`,
    ].join('\n');
  });

  return { content, count };
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

function transformFile(filePath) {
  console.log(`Transforming: ${filePath}`);

  let content = fs.readFileSync(filePath, 'utf-8');

  const r1 = wrapCreateTypes(content);
  content = r1.content;

  const r2 = wrapConstraints(content);
  content = r2.content;

  const r3 = addDropPolicies(content);
  content = r3.content;

  const r4 = addIndexIfNotExists(content);
  content = r4.content;

  const r5 = wrapPublicationAddTable(content);
  content = r5.content;

  const r6 = stripAuthTriggers(content);
  content = r6.content;

  const r7 = wrapAddColumn(content);
  content = r7.content;

  const totalChanges = r1.count + r2.count + r3.count + r4.count + r5.count + r6.count + r7.count;

  if (totalChanges === 0) {
    console.log('  No transformations needed.\n');
    return;
  }

  fs.writeFileSync(filePath, content, 'utf-8');

  console.log(`  CREATE TYPE     → IF NOT EXISTS wrappers:   ${r1.count}`);
  console.log(`  ADD CONSTRAINT  → IF NOT EXISTS wrappers:   ${r2.count}`);
  console.log(`  CREATE POLICY   → DROP IF EXISTS prepended: ${r3.count}`);
  console.log(`  CREATE INDEX    → IF NOT EXISTS added:       ${r4.count}`);
  console.log(`  ADD TABLE (pub) → IF NOT EXISTS wrappers:   ${r5.count}`);
  console.log(`  AUTH triggers   → stripped (manual apply):   ${r6.count}`);
  console.log(`  ADD COLUMN      → IF NOT EXISTS added:       ${r7.count}`);
  console.log('');
}

const targets = resolveTargets();

for (const filePath of targets) {
  transformFile(filePath);
}

console.log('Done.');
